#include <vector>
#include <queue>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<long long, long long>>> adj(n);

    // Build the adjacency list
    for (auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        long long cost = edge[2];
        if (online[u] && online[v]) {
            adj[u].push_back({v, cost});
        }
    }

    // Use a max-heap to keep track of the maximum minimum edge cost
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, less<pair<long long, int>>> maxHeap;
    maxHeap.push({0, 0}); // (minimum edge cost, node)

    // Keep track of visited nodes and the maximum minimum edge cost to reach them
    vector<long long> maxMinCost(n, LLONG_MIN);
    maxMinCost[0] = 0;

    while (!maxHeap.empty()) {
        long long currMin = maxHeap.top().first;
        int currNode = maxHeap.top().second;
        maxHeap.pop();

        if (currNode == n - 1) {
            return currMin;
        }

        if (currMin < maxMinCost[currNode]) {
            continue;
        }

        for (auto& neighbor : adj[currNode]) {
            int nextNode = neighbor.first;
            long long edgeCost = neighbor.second;
            long long newMin = min(currMin, edgeCost);

            if (online[nextNode] && newMin <= k && newMin > maxMinCost[nextNode]) {
                maxMinCost[nextNode] = newMin;
                maxHeap.push({newMin, nextNode});
            }
        }
    }

    return -1;
}

